import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { SERVICES, AMC_PLANS } from '../constants';
import { Calendar, Clock, MapPin, User, Phone, CheckCircle, CreditCard, Loader2, AlertCircle } from 'lucide-react';

const Booking: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { addBooking, user } = useApp();

  const preSelectedServiceId = searchParams.get('service');
  const preSelectedPlanId = searchParams.get('plan');

  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Determine default type and ID
  const defaultType = preSelectedPlanId ? 'amc' : 'one-time';
  // If no params, default to first service
  const defaultId = preSelectedPlanId || preSelectedServiceId || (defaultType === 'one-time' ? SERVICES[0].id : AMC_PLANS[0].id);

  const [formData, setFormData] = useState({
    name: user?.name || '',
    phone: user?.phone || '',
    email: user?.email || '',
    address: '',
    serviceType: defaultType,
    selectedId: defaultId,
    acType: 'Split',
    date: '',
    time: '',
    notes: ''
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    // Clear error for this field if it exists
    if (errors[e.target.name]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[e.target.name];
        return newErrors;
      });
    }
  };

  const handleServiceTypeChange = (type: 'one-time' | 'amc') => {
    setFormData({ 
      ...formData, 
      serviceType: type, 
      selectedId: type === 'one-time' ? SERVICES[0].id : AMC_PLANS[0].id 
    });
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.phone.trim()) newErrors.phone = "Phone is required";
    else if (!/^\d{10}$/.test(formData.phone)) newErrors.phone = "Enter a valid 10-digit phone number";

    if (!formData.address.trim()) newErrors.address = "Address is required";
    if (!formData.date) newErrors.date = "Date is required";
    if (!formData.time) newErrors.time = "Time slot is required";
    if (!formData.selectedId) newErrors.selectedId = "Please select a service or plan";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      setStep(2);
    }
  };

  const processPayment = () => {
    setLoading(true);
    setTimeout(() => {
      // Create booking object
      addBooking({
        customerName: formData.name,
        customerPhone: formData.phone,
        customerAddress: formData.address,
        serviceId: formData.serviceType === 'one-time' ? formData.selectedId : undefined,
        planId: formData.serviceType === 'amc' ? formData.selectedId : undefined,
        date: formData.date,
        time: formData.time,
        acType: formData.acType as any,
        notes: formData.notes
      });
      setLoading(false);
      setStep(3); // Success
    }, 2000);
  };

  const getSelectedItem = () => {
    if (formData.serviceType === 'one-time') {
      return SERVICES.find(s => s.id === formData.selectedId);
    }
    return AMC_PLANS.find(p => p.id === formData.selectedId);
  };

  const selectedItem = getSelectedItem();

  return (
    <div className="min-h-screen bg-gray-50 py-12">
      <div className="max-w-3xl mx-auto px-4">

        {/* Progress Steps */}
        <div className="flex items-center justify-center mb-10">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${step >= 1 ? 'bg-brand-600 text-white' : 'bg-gray-200 text-gray-500'}`}>1</div>
          <div className={`w-16 h-1 bg-gray-200 ${step >= 2 ? 'bg-brand-600' : ''}`}></div>
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${step >= 2 ? 'bg-brand-600 text-white' : 'bg-gray-200 text-gray-500'}`}>2</div>
          <div className={`w-16 h-1 bg-gray-200 ${step >= 3 ? 'bg-brand-600' : ''}`}></div>
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${step >= 3 ? 'bg-green-600 text-white' : 'bg-gray-200 text-gray-500'}`}>3</div>
        </div>

        <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
          {/* STEP 1: Details Form */}
          {step === 1 && (
            <div className="p-8">
              <h2 className="text-2xl font-bold text-gray-900 mb-6">Book Your Service</h2>
              <form onSubmit={handleSubmit} className="space-y-6">

                {/* Service Selection Toggle */}
                <div className="flex bg-gray-100 p-1 rounded-lg mb-6">
                  <button
                    type="button"
                    className={`flex-1 py-2 rounded-md font-semibold text-sm transition-all ${formData.serviceType === 'one-time' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    onClick={() => handleServiceTypeChange('one-time')}
                  >
                    One-Time Service
                  </button>
                  <button
                    type="button"
                    className={`flex-1 py-2 rounded-md font-semibold text-sm transition-all ${formData.serviceType === 'amc' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    onClick={() => handleServiceTypeChange('amc')}
                  >
                    AMC Plan
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Select {formData.serviceType === 'one-time' ? 'Service' : 'Plan'}</label>
                    <select
                      name="selectedId"
                      value={formData.selectedId}
                      onChange={handleInputChange}
                      className={`w-full rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.selectedId ? 'border-red-500' : 'border-gray-300'}`}
                    >
                      {formData.serviceType === 'one-time' 
                        ? SERVICES.map(s => <option key={s.id} value={s.id}>{s.title} - ₹{s.price}</option>)
                        : AMC_PLANS.map(p => <option key={p.id} value={p.id}>{p.title} - ₹{p.price}/yr</option>)
                      }
                    </select>
                    {errors.selectedId && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.selectedId}</p>}
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">AC Type</label>
                    <select
                      name="acType"
                      value={formData.acType}
                      onChange={handleInputChange}
                      className="w-full rounded-lg border-gray-300 shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 border"
                    >
                      <option value="Split">Split AC</option>
                      <option value="Window">Window AC</option>
                      <option value="Cassette">Cassette AC</option>
                      <option value="Tower">Tower AC</option>
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Calendar size={18} className="text-gray-400"/>
                      </div>
                      <input
                        type="date"
                        name="date"
                        value={formData.date}
                        onChange={handleInputChange}
                        className={`w-full pl-10 rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.date ? 'border-red-500' : 'border-gray-300'}`}
                      />
                    </div>
                    {errors.date && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.date}</p>}
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Time Slot</label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Clock size={18} className="text-gray-400"/>
                      </div>
                      <select
                        name="time"
                        value={formData.time}
                        onChange={handleInputChange}
                        className={`w-full pl-10 rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.time ? 'border-red-500' : 'border-gray-300'}`}
                      >
                        <option value="">Select Time</option>
                        <option value="09:00 AM - 11:00 AM">09:00 AM - 11:00 AM</option>
                        <option value="11:00 AM - 01:00 PM">11:00 AM - 01:00 PM</option>
                        <option value="02:00 PM - 04:00 PM">02:00 PM - 04:00 PM</option>
                        <option value="04:00 PM - 06:00 PM">04:00 PM - 06:00 PM</option>
                        <option value="06:00 PM - 08:00 PM">06:00 PM - 08:00 PM</option>
                      </select>
                    </div>
                    {errors.time && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.time}</p>}
                  </div>
                </div>

                <div className="border-t border-gray-100 pt-6 mt-6">
                  <h3 className="text-lg font-semibold mb-4">Personal Details</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <User size={18} className="text-gray-400"/>
                        </div>
                        <input
                          type="text"
                          name="name"
                          value={formData.name}
                          onChange={handleInputChange}
                          className={`w-full pl-10 rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.name ? 'border-red-500' : 'border-gray-300'}`}
                          placeholder="Your full name"
                        />
                      </div>
                      {errors.name && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.name}</p>}
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Phone Number</label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <Phone size={18} className="text-gray-400"/>
                        </div>
                        <input
                          type="tel"
                          name="phone"
                          value={formData.phone}
                          onChange={handleInputChange}
                          className={`w-full pl-10 rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.phone ? 'border-red-500' : 'border-gray-300'}`}
                          placeholder="10 digit mobile number"
                        />
                      </div>
                      {errors.phone && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.phone}</p>}
                    </div>
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Address</label>
                    <div className="relative">
                      <div className="absolute top-3 left-3 pointer-events-none">
                        <MapPin size={18} className="text-gray-400"/>
                      </div>
                      <textarea
                        name="address"
                        value={formData.address}
                        onChange={handleInputChange}
                        rows={3}
                        className={`w-full pl-10 rounded-lg border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-2.5 px-3 ${errors.address ? 'border-red-500' : 'border-gray-300'}`}
                        placeholder="Complete address with landmark"
                      ></textarea>
                    </div>
                    {errors.address && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.address}</p>}
                  </div>
                </div>

                <button 
                  type="submit"
                  className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 px-4 rounded-lg shadow-lg transition-colors flex items-center justify-center gap-2 text-lg"
                >
                  Proceed to Payment
                </button>
              </form>
            </div>
          )}

          {/* STEP 2: Payment Mock */}
          {step === 2 && (
            <div className="p-8">
              <h2 className="text-2xl font-bold text-gray-900 mb-6">Payment Summary</h2>

              <div className="bg-blue-50 p-6 rounded-xl border border-blue-100 mb-8 shadow-sm">
                <div className="flex justify-between items-center mb-3">
                  <span className="font-semibold text-gray-600">Service:</span>
                  <span className="font-bold text-brand-700 text-lg">{selectedItem?.title}</span>
                </div>
                <div className="flex justify-between items-center mb-3">
                  <span className="font-semibold text-gray-600">AC Type:</span>
                  <span className="font-medium text-brand-700">{formData.acType}</span>
                </div>
                <div className="flex justify-between items-center mb-4 pb-4 border-b border-blue-200">
                  <span className="font-semibold text-gray-600">Date & Time:</span>
                  <span className="font-medium text-brand-700">{formData.date} | {formData.time}</span>
                </div>
                <div className="flex justify-between items-center text-lg">
                  <span className="font-bold text-gray-900">Total Amount:</span>
                  <span className="font-extrabold text-brand-600 text-2xl">₹{selectedItem?.price}</span>
                </div>
              </div>

              <div className="space-y-4">
                 <h3 className="font-semibold text-gray-700">Select Payment Method</h3>
                 <div className="grid grid-cols-2 gap-4">
                    <button onClick={processPayment} className="border p-4 rounded-lg hover:border-brand-500 hover:bg-brand-50 flex flex-col items-center justify-center gap-2 transition-all group">
                       <CreditCard className="text-gray-400 group-hover:text-brand-500" size={24} />
                       <span className="font-medium text-sm">Card</span>
                    </button>
                    <button onClick={processPayment} className="border p-4 rounded-lg hover:border-brand-500 hover:bg-brand-50 flex flex-col items-center justify-center gap-2 transition-all group">
                       <span className="font-bold text-xl text-gray-400 group-hover:text-brand-500">UPI</span>
                       <span className="font-medium text-sm">UPI / QR</span>
                    </button>
                 </div>

                 <div className="mt-8 text-center">
                    {loading ? (
                      <button disabled className="w-full bg-gray-400 text-white font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 cursor-not-allowed">
                        <Loader2 className="animate-spin" /> Processing...
                      </button>
                    ) : (
                      <button onClick={processPayment} className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-4 rounded-lg shadow-lg flex items-center justify-center gap-2 text-lg">
                        Pay ₹{selectedItem?.price}
                      </button>
                    )}
                 </div>

                 <div className="text-center mt-4">
                    <button onClick={() => setStep(1)} className="text-sm text-gray-500 hover:text-brand-600 underline">Back to details</button>
                 </div>
              </div>
            </div>
          )}

          {/* STEP 3: Success */}
          {step === 3 && (
            <div className="p-12 text-center flex flex-col items-center justify-center">
               <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center text-green-600 mb-6 animate-bounce">
                  <CheckCircle size={48} />
               </div>
               <h2 className="text-3xl font-bold text-gray-900 mb-4">Booking Confirmed!</h2>
               <p className="text-gray-600 mb-8 max-w-md">
                 Thank you, {formData.name}. Your booking for <strong>{selectedItem?.title}</strong> has been confirmed. Our technician will arrive at the scheduled time.
               </p>
               <div className="flex gap-4">
                  <button onClick={() => navigate('/')} className="px-6 py-2 border border-gray-300 rounded-lg font-semibold hover:bg-gray-50">Back to Home</button>
                  <button onClick={() => navigate('/dashboard')} className="px-6 py-2 bg-brand-600 text-white rounded-lg font-semibold hover:bg-brand-700 shadow-md">Go to Dashboard</button>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

