import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, Booking, UserRole, BookingStatus } from '../types';

interface AppContextType {
  user: User | null;
  login: (email: string, role: UserRole) => void;
  logout: () => void;
  bookings: Booking[];
  addBooking: (booking: Omit<Booking, 'id' | 'createdAt' | 'status' | 'userId'>) => void;
  updateBookingStatus: (id: string, status: BookingStatus) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const STORAGE_KEYS = {
  USER: 'ac_services_user',
  BOOKINGS: 'ac_services_bookings'
};

const INITIAL_BOOKINGS: Booking[] = [
  {
    id: 'bk_123',
    userId: 'u_1',
    customerName: 'Rajesh Koothrappali',
    customerPhone: '9876543210',
    customerAddress: 'Flat 402, DLF Phase 4, Gurugram',
    serviceId: 'repair',
    date: '2023-11-20',
    time: '10:00 AM',
    status: BookingStatus.PENDING,
    acType: 'Split',
    notes: 'AC not cooling properly',
    createdAt: new Date().toISOString()
  },
  {
    id: 'bk_124',
    userId: 'u_2',
    customerName: 'Penny Smith',
    customerPhone: '9123456789',
    customerAddress: 'Villa 12, Nirvana Country, Gurugram',
    planId: 'standard',
    date: '2023-11-22',
    time: '02:00 PM',
    status: BookingStatus.CONFIRMED,
    acType: 'Window',
    createdAt: new Date().toISOString()
  }
];

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [isInitialized, setIsInitialized] = useState(false);

  // Load initial data from localStorage
  useEffect(() => {
    const storedUser = localStorage.getItem(STORAGE_KEYS.USER);
    const storedBookings = localStorage.getItem(STORAGE_KEYS.BOOKINGS);

    if (storedUser) {
      try {
        setUser(JSON.parse(storedUser));
      } catch (e) {
        console.error("Failed to parse user from storage", e);
      }
    }

    if (storedBookings) {
      try {
        setBookings(JSON.parse(storedBookings));
      } catch (e) {
        console.error("Failed to parse bookings from storage", e);
        setBookings(INITIAL_BOOKINGS);
      }
    } else {
      setBookings(INITIAL_BOOKINGS);
      localStorage.setItem(STORAGE_KEYS.BOOKINGS, JSON.stringify(INITIAL_BOOKINGS));
    }

    setIsInitialized(true);
  }, []);

  // Persist user on change (only if initialized to avoid overwriting with null on mount)
  useEffect(() => {
    if (isInitialized) {
      if (user) {
        localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(user));
      } else {
        localStorage.removeItem(STORAGE_KEYS.USER);
      }
    }
  }, [user, isInitialized]);

  // Persist bookings on change
  useEffect(() => {
    if (isInitialized) {
      localStorage.setItem(STORAGE_KEYS.BOOKINGS, JSON.stringify(bookings));
    }
  }, [bookings, isInitialized]);

  const login = (email: string, role: UserRole) => {
    const newUser = {
      id: email.split('@')[0], // Simple ID generation based on email
      name: email.split('@')[0],
      email,
      role
    };
    setUser(newUser);
  };

  const logout = () => {
    setUser(null);
  };

  const addBooking = (newBookingData: Omit<Booking, 'id' | 'createdAt' | 'status' | 'userId'>) => {
    const newBooking: Booking = {
      ...newBookingData,
      id: Math.random().toString(36).substr(2, 9),
      userId: user?.id || null,
      status: BookingStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    setBookings(prev => [newBooking, ...prev]);
  };

  const updateBookingStatus = (id: string, status: BookingStatus) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
  };

  return (
    <AppContext.Provider value={{ user, login, logout, bookings, addBooking, updateBookingStatus }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

