import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { User, Booking, UserRole, BookingStatus } from '../types';

interface AppContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<{ success: boolean; message?: string }>;
  signup: (userData: User) => Promise<{ success: boolean; message?: string }>;
  logout: () => void;
  forgotPassword: (email: string) => Promise<{ success: boolean; message?: string }>;
  resetPassword: (token: string, password: string) => Promise<{ success: boolean; message?: string }>;
  bookings: Booking[];
  addBooking: (booking: Omit<Booking, 'id' | 'createdAt' | 'status' | 'userId'>) => void;
  updateBookingStatus: (id: string, status: BookingStatus) => void;
  refreshData: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

// --- MOCK DATA HANDLERS (For when backend is offline) ---
const MOCK_STORAGE_KEYS = {
  USERS: 'ac_app_mock_users',
  BOOKINGS: 'ac_app_mock_bookings',
  TOKEN: 'token'
};

const getMockUsers = (): User[] => {
  const stored = localStorage.getItem(MOCK_STORAGE_KEYS.USERS);
  return stored ? JSON.parse(stored) : [];
};

const getMockBookings = (): Booking[] => {
  const stored = localStorage.getItem(MOCK_STORAGE_KEYS.BOOKINGS);
  return stored ? JSON.parse(stored) : [];
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [useMock, setUseMock] = useState(false);

  // Helper to get token
  const getToken = () => localStorage.getItem('token');

  const fetchBookings = useCallback(async () => {
    if (useMock) {
      const allBookings = getMockBookings();
      if (user?.role === UserRole.ADMIN) {
        setBookings(allBookings.sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()));
      } else if (user) {
        setBookings(allBookings.filter(b => b.userId === user.id).sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()));
      }
      return;
    }

    const token = getToken();
    if (!token) {
      setBookings([]);
      return;
    }

    try {
      // Set a short timeout for the fetch to detect backend failure quickly
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 2000);

      const response = await fetch('/api/bookings', {
        headers: {
          'Authorization': `Bearer ${token}`
        },
        signal: controller.signal
      });
      clearTimeout(timeoutId);

      if (response.ok) {
        const data = await response.json();
        setBookings(data);
      } else {
        throw new Error('API Error');
      }
    } catch (error) {
      console.warn("Backend unavailable, switching to mock data for bookings.");
      setUseMock(true); // Switch to mock mode if backend fails
    }
  }, [useMock, user]);

  const loadUser = useCallback(async () => {
    const token = getToken();
    if (!token) {
      return;
    }

    // If we are already in mock mode, load from local storage
    if (useMock) {
      const mockUsers = getMockUsers();
      // Simple decode simulation: assume token is just user ID in mock mode or find by matching token
      // For simplicity in mock mode, we store the 'user' object in local storage when logging in
      const savedUser = localStorage.getItem('mock_current_user');
      if (savedUser) setUser(JSON.parse(savedUser));
      fetchBookings();
      return;
    }

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 2000);

      const response = await fetch('/api/auth/me', {
        headers: {
          'Authorization': `Bearer ${token}`
        },
        signal: controller.signal
      });
      clearTimeout(timeoutId);

      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
        await fetchBookings();
      } else {
        // Token invalid or server error
        if (response.status === 401) {
           localStorage.removeItem('token');
           setUser(null);
        } else {
           throw new Error("Server error");
        }
      }
    } catch (error) {
      console.warn("Backend unavailable, switching to mock data.");
      setUseMock(true);

      // Fallback: Try to load mock user if exists
      const savedUser = localStorage.getItem('mock_current_user');
      if (savedUser) {
        setUser(JSON.parse(savedUser));
        // Force a re-fetch of mock bookings
        const allBookings = getMockBookings();
        setBookings(allBookings);
      }
    }
  }, [fetchBookings, useMock]);

  useEffect(() => {
    loadUser();
  }, [loadUser]);

  const login = async (email: string, password: string): Promise<{ success: boolean; message?: string }> => {
    // 1. Try API
    if (!useMock) {
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000);

        const response = await fetch('/api/auth/login', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email, password }),
          signal: controller.signal
        });
        clearTimeout(timeoutId);

        const data = await response.json();

        if (response.ok) {
          localStorage.setItem('token', data.token);
          setUser(data);
          await fetchBookings();
          return { success: true };
        } else {
          // If 401, it's a real auth error, don't switch to mock
          if (response.status === 401) return { success: false, message: data.message || 'Invalid credentials' };
          throw new Error('Network error');
        }
      } catch (error) {
        console.warn("Login failed (Network), switching to mock.");
        setUseMock(true);
        // Fall through to mock logic
      }
    }

    // 2. Mock Logic
    const mockUsers = getMockUsers();
    // Default Admin for Mock Mode
    if (email === 'admin@aaron.com' && password === 'admin123') {
       const adminUser: User = { id: 'admin-1', name: 'Admin User', email, role: UserRole.ADMIN, phone: '0000000000' };
       setUser(adminUser);
       localStorage.setItem('token', 'mock-admin-token');
       localStorage.setItem('mock_current_user', JSON.stringify(adminUser));
       return { success: true };
    }

    const foundUser = mockUsers.find(u => u.email === email && u.password === password);
    if (foundUser) {
      const safeUser = { ...foundUser, password: '' }; // Remove password from state
      setUser(safeUser);
      localStorage.setItem('token', `mock-token-${foundUser.id}`);
      localStorage.setItem('mock_current_user', JSON.stringify(safeUser));
      fetchBookings(); // Loads mock bookings
      return { success: true };
    }

    return { success: false, message: 'Invalid email or password (Mock Mode)' };
  };

  const signup = async (userData: User): Promise<{ success: boolean; message?: string }> => {
    if (!useMock) {
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000);

        const response = await fetch('/api/auth/register', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: userData.name,
            email: userData.email,
            phone: userData.phone,
            password: userData.password
          }),
          signal: controller.signal
        });
        clearTimeout(timeoutId);

        const data = await response.json();

        if (response.ok) {
          localStorage.setItem('token', data.token);
          setUser(data);
          return { success: true };
        } else {
          return { success: false, message: data.message || 'Signup failed' };
        }
      } catch (error) {
        console.warn("Signup failed (Network), switching to mock.");
        setUseMock(true);
      }
    }

    // Mock Logic
    const mockUsers = getMockUsers();
    if (mockUsers.find(u => u.email === userData.email)) {
      return { success: false, message: 'User already exists' };
    }

    const newUser = { 
      ...userData, 
      id: Date.now().toString(), 
      role: userData.email.includes('admin') ? UserRole.ADMIN : UserRole.CUSTOMER 
    };

    mockUsers.push(newUser);
    localStorage.setItem(MOCK_STORAGE_KEYS.USERS, JSON.stringify(mockUsers));

    // Auto login
    const safeUser = { ...newUser, password: '' };
    setUser(safeUser);
    localStorage.setItem('token', `mock-token-${newUser.id}`);
    localStorage.setItem('mock_current_user', JSON.stringify(safeUser));

    return { success: true };
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('mock_current_user');
    setUser(null);
    setBookings([]);
  };

  const forgotPassword = async (email: string): Promise<{ success: boolean; message?: string }> => {
    if (!useMock) {
      try {
        const response = await fetch('/api/auth/forgotpassword', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email })
        });
        const data = await response.json();
        if (response.ok) return { success: true, message: data.data };
        // If fail, we can optionally fall back to mock or just return error
        if (response.status === 404) return { success: false, message: 'User not found' };
      } catch (e) {
        setUseMock(true);
      }
    }

    // Mock Logic
    return { success: true, message: 'If the email exists, a reset link has been sent (Mock).' };
  };

  const resetPassword = async (token: string, password: string): Promise<{ success: boolean; message?: string }> => {
    if (!useMock) {
      try {
        const response = await fetch(`/api/auth/resetpassword/${token}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ password })
        });
        const data = await response.json();
        if (response.ok) return { success: true };
        return { success: false, message: data.message };
      } catch (e) {
        setUseMock(true);
      }
    }
    return { success: true, message: 'Password has been reset (Mock).' };
  };

  const addBooking = async (newBookingData: Omit<Booking, 'id' | 'createdAt' | 'status' | 'userId'>) => {
    if (!useMock) {
      try {
        const token = getToken();
        if (!token) return;

        const response = await fetch('/api/bookings', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
          body: JSON.stringify(newBookingData)
        });

        if (response.ok) {
          await fetchBookings();
          return;
        }
      } catch (e) {
        setUseMock(true);
      }
    }

    // Mock Logic
    const mockBookings = getMockBookings();
    const newBooking: Booking = {
      ...newBookingData,
      id: Date.now().toString(),
      createdAt: new Date().toISOString(),
      status: BookingStatus.PENDING,
      userId: user?.id || null
    };
    mockBookings.push(newBooking);
    localStorage.setItem(MOCK_STORAGE_KEYS.BOOKINGS, JSON.stringify(mockBookings));

    // Update state directly for immediate feedback
    if (user?.role === UserRole.ADMIN) {
      setBookings(prev => [newBooking, ...prev]);
    } else {
      setBookings(prev => [newBooking, ...prev]);
    }
  };

  const updateBookingStatus = async (id: string, status: BookingStatus) => {
    if (!useMock) {
      try {
        const token = getToken();
        if (!token) return;

        const response = await fetch(`/api/bookings/${id}`, {
          method: 'PATCH',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
          body: JSON.stringify({ status })
        });

        if (response.ok) {
          setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
          return;
        }
      } catch (e) {
        setUseMock(true);
      }
    }

    // Mock Logic
    const mockBookings = getMockBookings();
    const index = mockBookings.findIndex(b => b.id === id);
    if (index !== -1) {
      mockBookings[index].status = status;
      localStorage.setItem(MOCK_STORAGE_KEYS.BOOKINGS, JSON.stringify(mockBookings));
      setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    }
  };

  const refreshData = () => {
    fetchBookings();
  };

  return (
    <AppContext.Provider value={{ 
      user, login, signup, logout, forgotPassword, resetPassword, 
      bookings, addBooking, updateBookingStatus, refreshData 
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

